#!/usr/bin/env node

import { createHash } from "node:crypto";
import { mkdir, readFile, writeFile } from "node:fs/promises";
import path from "node:path";

const rootDir = process.cwd();
const sourcePath = path.join(rootDir, "scripts", "vchara-codex-worker.mjs");
const outputPath = path.join(rootDir, "src", "generated", "codex-worker-script-source.ts");

const script = await readFile(sourcePath, "utf8");
const metadata = {
  sha256: createHash("sha256").update(script).digest("hex"),
  bytes: Buffer.byteLength(script, "utf8"),
};

const output = [
  "// Generated by scripts/embed-codex-worker-script.mjs. Do not edit by hand.",
  "",
  `export const embeddedCodexWorkerScript = ${JSON.stringify(script)};`,
  "",
  "export const embeddedCodexWorkerScriptMetadata = {",
  `  sha256: ${JSON.stringify(metadata.sha256)},`,
  `  bytes: ${metadata.bytes},`,
  "} as const;",
  "",
].join("\n");

await mkdir(path.dirname(outputPath), { recursive: true });
await writeFile(outputPath, output);
